<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'; import { showFailToast } from 'vant'; import PageHeader from '../components/PageHeader.vue'; import { useAuthStore } from '../stores/auth'; import { getActiveActivity,getRecords } from '../services/api'; import type { Activity,ActivityUser,DailyRecord } from '../types'; import { formatCN,todayCN } from '../utils/date'; import { currentWeight,remainingDays,streak,totalLoss } from '../utils/metrics'
const auth=useAuthStore(); const activity=ref<Activity|null>(null); const member=ref<ActivityUser|null>(null); const records=ref<DailyRecord[]>([]); const loading=ref(true)
const today=computed(()=>records.value.find(r=>r.record_date===todayCN())); const current=computed(()=>member.value?currentWeight(member.value.initial_weight,records.value):0); const loss=computed(()=>member.value?totalLoss(member.value.initial_weight,current.value):0)
onMounted(async()=>{try{if(!auth.user)return; const result=await getActiveActivity(auth.user.id); activity.value=result.activity; member.value=result.membership; if(activity.value)records.value=await getRecords(auth.user.id,activity.value.id)}catch(e){showFailToast(e instanceof Error?e.message:'加载失败')}finally{loading.value=false}})
</script>
<template><section class="page"><PageHeader :eyebrow="formatCN(todayCN())" :title="`早上好，${auth.profile?.nickname||'朋友'}`"/><van-skeleton :loading="loading" title :row="6"><template v-if="activity&&member"><div class="card hero"><div class="eyebrow" style="color:#dcec7a">正在进行</div><h2>{{activity.activity_name}}</h2><p class="muted">{{activity.start_date}} — {{activity.end_date}}</p><div class="row"><strong>{{ remainingDays(activity.end_date) }} 天</strong><span>{{ today?'今日已打卡':'今天还未打卡' }}</span></div></div><div class="metric-grid"><div class="metric"><small>当前体重</small><b>{{current}}<small> kg</small></b></div><div class="metric"><small>累计减重</small><b>{{loss>0?'-':''}}{{Math.abs(loss)}}<small> kg</small></b></div><div class="metric"><small>目标体重</small><b>{{member.target_weight}}<small> kg</small></b></div><div class="metric"><small>连续打卡</small><b>{{streak(records)}}<small> 天</small></b></div></div><div style="height:14px"></div><button class="primary-btn" @click="$router.push('/checkin')">{{today?'修改今日打卡':'开始今日打卡'}}</button><h3 class="section-title">你的进度</h3><div class="card"><div class="row"><span>从 {{member.initial_weight}} kg 开始</span><span class="tag">目标 {{member.target_weight}} kg</span></div><van-progress style="margin-top:18px" :percentage="Math.max(0,Math.min(100,(member.initial_weight-current)/(member.initial_weight-member.target_weight)*100||0))" stroke-width="10" color="#1f765c"/></div><div class="row"><button class="secondary-btn" @click="$router.push('/trend')">查看体重趋势</button></div></template><div v-else class="card empty">目前没有进行中的活动，请联系管理员。</div></van-skeleton></section></template>
